    for (let r = 0; r < 9; r++) {
        for (let c = 0; c < 9; c++) {
            const d = board[r][c];
            if (d === '.') continue;
            const box = Math.floor(r / 3) * 3 + Math.floor(c / 3);
            if (rows[r].has(d) || cols[c].has(d) || boxes[box].has(d)) return false;
            rows[r].add(d);
            cols[c].add(d);
            boxes[box].add(d);
        }
    }
    return true;
};

