class Solution:
    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:
        root = {}
        for word in words:
            node = root
            for c in word:
                node = node.setdefault(c, {})
            node['#'] = word
        m, n = len(board), len(board[0])
        result = []
        def dfs(r, c, node):
            if r < 0 or r >= m or c < 0 or c >= n:
                return
            char = board[r][c]
            if char not in node:
                return
            next_node = node[char]
            if '#' in next_node:
                result.append(next_node['#'])
                del next_node['#']
            board[r][c] = '.'
            for dr, dc in [(0,1),(0,-1),(1,0),(-1,0)]:
                dfs(r + dr, c + dc, next_node)
            board[r][c] = char
            if not next_node:
                del node[char]
        for r in range(m):
            for c in range(n):
                dfs(r, c, root)
        return result

